questionvariables.text:
dp(x, n) := float(round((x+10^(-8))*10^n)/10^n);

plots: 30+rand(10);
variety: 4+rand(3);
weeding: 2+rand(2);
fert: 3+rand(2);
variety_df:variety-1;
weeding_df: weeding-1;
fert_df: fert-1;
total_df: plots-1;
resid_df: total_df-weeding_df-variety_df-fert_df;

variety_ss: dp(float((rand(10)/10)+(rand(10)+20)),1);
weeding_ss: dp(float((rand(10)/10)+(rand(10)+10)),1);
fert_ss: dp(float((rand(10)/10)+rand(6)+40),1);
resid_ss: dp(float((rand(10)/10)+(rand(20)+65)),1);
total_ss: dp(variety_ss+weeding_ss+fert_ss+resid_ss,1);

variety_ms: dp(variety_ss/variety_df,1);
weeding_ms: dp(weeding_ss/weeding_df,1);
fert_ms: dp(fert_ss/fert_df,1);
resid_ms: dp(resid_ss/resid_df,1);

variety_f: dp(variety_ms/resid_ms,1);
weeding_f: dp(weeding_ms/resid_ms,1);
fert_f: dp(fert_ms/resid_ms,1);

variety_variation: dp(variety_ss/total_ss * 100, 1)
unaccounted_variation: dp(resid_ss/total_ss * 100, 1)

ta1: variety_variation;
ta2: unaccounted_variation;
